module RefModule(
    input clk,
    input reset,
    input start,
    input receive,
    input forward,
    output reg [1:0] current_state
);
    // State encoding
    parameter IDLE = 2'b00, LISTENING = 2'b01, LEARNING = 2'b10, FORWARDING = 2'b11;
    reg [1:0] ctrl_bus_wire;

    // State transition logic
    always @(*) begin
        case (current_state)
            IDLE: begin
                if (start) ctrl_bus_wire = LISTENING;
                else ctrl_bus_wire = IDLE;
            end
            LISTENING: begin
                if (receive) ctrl_bus_wire = LEARNING;
                else ctrl_bus_wire = LISTENING;
            end
            LEARNING: begin
                if (forward) ctrl_bus_wire = FORWARDING;
                else ctrl_bus_wire = LEARNING;
            end
            FORWARDING: begin
                ctrl_bus_wire = IDLE; // transition back to IDLE for demo purposes
            end
            default: ctrl_bus_wire = IDLE;
        endcase
    end

    // State update logic
    always @(posedge clk or posedge reset) begin
        if (reset)
            current_state <= IDLE;
        else
            current_state <= ctrl_bus_wire;
    end
endmodule
